 1в†’/**
 2в†’ * Backend Config -- deployment mode detection and endpoint resolution.
 3в†’ *
 4в†’ * Determines how the frontend connects to the backend based on environment:
 5в†’ * - Electron: localhost WS + HTTP via IPC-resolved port
 6в†’ * - Web-dev: localhost WS + HTTP via VITE_BACKEND_PORT
 7в†’ * - Web-production (relay): WS through relay.rundeus.com, HTTP tunneled over WS
 8в†’ *
 9в†’ * The resolved endpoints are cached after first call.
10в†’ */
11в†’
12в†’import { capabilities } from "@/platform/capabilities";
13в†’import { getBackendPort } from "./api.config";
14в†’
15в†’export type DeploymentMode = "electron" | "web-dev" | "web-production";
16в†’
17в†’/** Detect the current deployment mode. */
18в†’export function getDeploymentMode(): DeploymentMode {
19в†’  if (capabilities.ipcInvoke) return "electron";
20в†’  if (import.meta.env.VITE_BACKEND_PORT) return "web-dev";
21в†’  return "web-production";
22в†’}
23в†’
24в†’/** Whether the frontend is connecting through the cloud relay. */
25в†’export function isRelayMode(): boolean {
26в†’  return getDeploymentMode() === "web-production";
27в†’}
28в†’
29в†’export interface BackendEndpoints {
30в†’  wsUrl: string;
31в†’  apiBase: string;
32в†’}
33в†’
34в†’export const RELAY_BASE_URL =
35в†’  (import.meta.env.VITE_RELAY_URL as string | undefined) || "wss://relay.rundeus.com";
36в†’
37в†’let cachedEndpoints: BackendEndpoints | null = null;
38в†’/** The serverId that the cached endpoints were built for (relay mode only). */
39в†’let cachedRelayServerId: string | null = null;
40в†’
41в†’/**
42в†’ * Resolve the backend's WebSocket and HTTP base URLs.
43в†’ *
44в†’ * - Electron/web-dev: ws://localhost:{port}/ws + http://localhost:{port}/api
45в†’ * - Web-production: wss://relay.rundeus.com/api/servers/{serverId}/connect
46в†’ *   (HTTP goes through WS bridge, so apiBase is unused in relay mode)
47в†’ */
48в†’export async function resolveBackendEndpoints(serverId?: string): Promise<BackendEndpoints> {
49в†’  const mode = getDeploymentMode();
50в†’
51в†’  if (mode === "web-production") {
52в†’    // In relay mode, serverId comes from the URL (/s/{serverId}/...)
53в†’    // or can be passed explicitly.
54в†’    const id = serverId || getServerIdFromUrl();
55в†’    if (!id) {
56в†’      throw new Error("No server ID available for relay connection");
57в†’    }
58в†’    // Cache is per-serverId вЂ” invalidate if serverId changes (strict equality)
59в†’    if (cachedEndpoints && cachedRelayServerId === id) {
60в†’      return cachedEndpoints;
61в†’    }
62в†’    const encodedId = encodeURIComponent(id);
63в†’    cachedRelayServerId = id;
64в†’    cachedEndpoints = {
65в†’      wsUrl: `${RELAY_BASE_URL}/api/servers/${encodedId}/connect`,
66в†’      // In relay mode, HTTP is tunneled over WS вЂ” apiBase is a placeholder
67в†’      // that should never be used directly (client.ts intercepts requests).
68в†’      apiBase: `${RELAY_BASE_URL}/api/servers/${encodedId}`,
69в†’    };
70в†’    return cachedEndpoints;
71в†’  }
72в†’
73в†’  // Electron or web-dev: resolve local port
74в†’  if (cachedEndpoints) return cachedEndpoints;
75в†’
76в†’  const port = await getBackendPort();
77в†’  cachedEndpoints = {
78в†’    wsUrl: `ws://localhost:${port}/ws`,
79в†’    apiBase: `http://localhost:${port}/api`,
80в†’  };
81в†’  return cachedEndpoints;
82в†’}
83в†’
84в†’function invalidateEndpointCache(): void {
85в†’  cachedEndpoints = null;
86в†’  cachedRelayServerId = null;
87в†’}
88в†’
89в†’/** Extract serverId from the current URL pathname (/s/{serverId}/...). */
90в†’function getServerIdFromUrl(): string | null {
91в†’  const match = window.location.pathname.match(/^\/s\/([^/]+)/);
92в†’  return match ? match[1] : null;
93в†’}
94в†’

 1в†’export const DEFAULT_RELAY_URL = "wss://relay.rundeus.com";
