 3в†’export function isLocalhost(ip: string | undefined): boolean {
 4в†’  if (!ip) return false;
 5в†’  return ip === "127.0.0.1" || ip === "::1" || ip === "::ffff:127.0.0.1" || ip === "localhost";
 6в†’}
 7в†’
 8в†’export function getClientIp(c: any): string | undefined {
 9в†’  return (
10в†’    (c.env as any)?.incoming?.socket?.remoteAddress ||
11в†’    c.req.header("x-forwarded-for")?.split(",")[0]?.trim() ||
12в†’    c.req.header("x-real-ip")
13в†’  );
14в†’}
