 1в†’// Deus Cloud Relay вЂ” Cloudflare Worker entry point.
 2в†’// Routes WebSocket upgrades to the RelayDO (one Durable Object per server).
 3в†’
 4в†’import { Hono } from "hono";
 5в†’import { cors } from "hono/cors";
 6в†’import { createMiddleware } from "hono/factory";
 7в†’import type { Bindings } from "./types";
 8в†’
 9в†’export { RelayDO } from "./relay-do";
10в†’
11в†’const app = new Hono<{ Bindings: Bindings }>();
12в†’
13в†’// CORS for web portal and local dev
14в†’app.use(
15в†’  "*",
16в†’  cors({
17в†’    origin: ["https://app.rundeus.com", "http://localhost:3000", "http://localhost:5173"],
18в†’    allowMethods: ["GET", "POST", "OPTIONS"],
19в†’    allowHeaders: ["Content-Type", "Authorization"],
20в†’  })
21в†’);
22в†’
23в†’// Middleware: validate serverId and attach DO stub to context
24в†’const withRelay = createMiddleware<{
25в†’  Bindings: Bindings;
26в†’  Variables: { stub: DurableObjectStub };
27в†’}>(async (c, next) => {
28в†’  const serverId = c.req.param("serverId");
29в†’  if (!serverId || !/^[a-z0-9]{4,8}$/i.test(serverId)) {
30в†’    return c.json({ error: "Invalid server ID" }, { status: 400 });
31в†’  }
32в†’  const id = c.env.RELAY.idFromName(serverId);
33в†’  c.set("stub", c.env.RELAY.get(id));
34в†’  await next();
35в†’});
36в†’
37в†’// Health check
38в†’app.get("/health", (c) =>
39в†’  c.json({
40в†’    status: "ok",
41в†’    timestamp: new Date().toISOString(),
42в†’    service: "deus-relay",
43в†’  })
44в†’);
45в†’
46в†’// Server tunnel вЂ” desktop server connects here to register with the relay
47в†’app.get("/api/servers/:serverId/tunnel", withRelay, async (c) => {
48в†’  const stub = c.get("stub");
49в†’  const tunnelUrl = new URL(c.req.url);
50в†’  tunnelUrl.pathname = "/tunnel";
51в†’  return stub.fetch(new Request(tunnelUrl, c.req.raw));
52в†’});
53в†’
54в†’// Client connect вЂ” remote web/mobile clients connect here
55в†’app.get("/api/servers/:serverId/connect", withRelay, async (c) => {
56в†’  const stub = c.get("stub");
57в†’  const connectUrl = new URL(c.req.url);
58в†’  connectUrl.pathname = "/connect";
59в†’  return stub.fetch(new Request(connectUrl, c.req.raw));
60в†’});
61в†’
62в†’// Pairing exchange вЂ” web portal exchanges a code for a device token
63в†’app.get("/api/servers/:serverId/pair", withRelay, async (c) => {
64в†’  const stub = c.get("stub");
65в†’  const pairUrl = new URL(c.req.url);
66в†’  pairUrl.pathname = "/pair";
67в†’  return stub.fetch(new Request(pairUrl, c.req.raw));
68в†’});
69в†’
70в†’// Server status вЂ” check if a server is online
71в†’app.get("/api/servers/:serverId/status", withRelay, async (c) => {
72в†’  const stub = c.get("stub");
73в†’  return stub.fetch(new Request(new URL("/status", c.req.url)));
74в†’});
75в†’
76в†’// Root
77в†’app.get("/", (c) =>
78в†’  c.json({
79в†’    name: "deus-relay",
80в†’    version: "0.1.0",
81в†’    docs: "https://app.rundeus.com",
82в†’  })
83в†’);
84в†’
85в†’export default app;
86в†’

 1в†’import Database from "better-sqlite3";
 2в†’import path from "path";
 3в†’import fs from "fs";
 4в†’import os from "os";
 5в†’import { SCHEMA_SQL, MIGRATIONS } from "@shared/schema";
 6в†’
 7в†’const DEFAULT_DB_PATH = path.join(
 8в†’  process.env.HOME || os.homedir(),
 9в†’  "Library/Application Support/com.deus.app/deus.db"
10в†’);
11в†’
12в†’const DB_PATH = process.env.DATABASE_PATH || DEFAULT_DB_PATH;
13в†’
14в†’let dbInstance: Database.Database | null = null;
15в†’
16в†’function initDatabase(): Database.Database {
17в†’  if (dbInstance) {
18в†’    return dbInstance;
19в†’  }
20в†’
21в†’  // Ensure parent directory exists (first launch)
22в†’  const dbDir = path.dirname(DB_PATH);
23в†’  if (!fs.existsSync(dbDir)) {
24в†’    fs.mkdirSync(dbDir, { recursive: true });
25в†’  }
26в†’
27в†’  console.log("Opening database:", DB_PATH);
28в†’
29в†’  try {
30в†’    dbInstance = new Database(DB_PATH);
31в†’    dbInstance.pragma("journal_mode = WAL");
32в†’    dbInstance.pragma("foreign_keys = ON");
33в†’    dbInstance.pragma("busy_timeout = 5000");
34в†’    dbInstance.pragma("optimize");
35в†’
36в†’    // Create all tables, indexes, and triggers (idempotent)
37в†’    dbInstance.exec(SCHEMA_SQL);
38в†’
39в†’    // Post-launch migrations: add new columns to existing tables.
40в†’    // Each ALTER TABLE may fail with "duplicate column" if already applied вЂ” skip those.
41в†’    for (const sql of MIGRATIONS) {
42в†’      try {
43в†’        dbInstance.exec(sql);
44в†’      } catch (e: unknown) {
45в†’        const msg = e instanceof Error ? e.message : "";
46в†’        if (!msg.includes("duplicate column") && !msg.includes("no such table")) throw e;
47в†’      }
48в†’    }
49в†’
50в†’    console.log("Database connected");
51в†’    return dbInstance;
52в†’  } catch (error) {
53в†’    console.error("Failed to open database:", error);
54в†’    throw error;
55в†’  }
56в†’}
57в†’
58в†’function getDatabase(): Database.Database {
59в†’  if (!dbInstance) {
60в†’    throw new Error("Database not initialized. Call initDatabase() first.");
61в†’  }
62в†’  return dbInstance;
63в†’}
64в†’
65в†’function closeDatabase(): void {
66в†’  if (dbInstance) {
67в†’    console.log("Closing database connection");
68в†’    dbInstance.pragma("optimize");
69в†’    dbInstance.close();
70в†’    dbInstance = null;
71в†’  }
72в†’}
73в†’
74в†’export { initDatabase, getDatabase, closeDatabase, DB_PATH };
