50в†’
51в†’  if (mode === "web-production") {
52в†’    // In relay mode, serverId comes from the URL (/s/{serverId}/...)
53в†’    // or can be passed explicitly.
54в†’    const id = serverId || getServerIdFromUrl();
55в†’    if (!id) {
56в†’      throw new Error("No server ID available for relay connection");
57в†’    }
58в†’    // Cache is per-serverId вЂ” invalidate if serverId changes (strict equality)
59в†’    if (cachedEndpoints && cachedRelayServerId === id) {
60в†’      return cachedEndpoints;
61в†’    }
62в†’    const encodedId = encodeURIComponent(id);
63в†’    cachedRelayServerId = id;
64в†’    cachedEndpoints = {
65в†’      wsUrl: `${RELAY_BASE_URL}/api/servers/${encodedId}/connect`,
66в†’      // In relay mode, HTTP is tunneled over WS вЂ” apiBase is a placeholder
67в†’      // that should never be used directly (client.ts intercepts requests).
68в†’      apiBase: `${RELAY_BASE_URL}/api/servers/${encodedId}`,
69в†’    };
70в†’    return cachedEndpoints;
71в†’  }
72в†’
73в†’  // Electron or web-dev: resolve local port
74в†’  if (cachedEndpoints) return cachedEndpoints;
75в†’
76в†’  const port = await getBackendPort();
77в†’  cachedEndpoints = {
78в†’    wsUrl: `ws://localhost:${port}/ws`,
79в†’    apiBase: `http://localhost:${port}/api`,
80в†’  };
81в†’  return cachedEndpoints;
82в†’}
83в†’
84в†’function invalidateEndpointCache(): void {
85в†’  cachedEndpoints = null;
86в†’  cachedRelayServerId = null;
87в†’}
88в†’
89в†’/** Extract serverId from the current URL pathname (/s/{serverId}/...). */
90в†’function getServerIdFromUrl(): string | null {
91в†’  const match = window.location.pathname.match(/^\/s\/([^/]+)/);
92в†’  return match ? match[1] : null;
93в†’}
94в†’

 1в†’export const DEFAULT_RELAY_URL = "wss://relay.rundeus.com";
 2в†’
 3в†’export function isLocalhost(ip: string | undefined): boolean {
 4в†’  if (!ip) return false;
 5в†’  return ip === "127.0.0.1" || ip === "::1" || ip === "::ffff:127.0.0.1" || ip === "localhost";
 6в†’}
 7в†’
 8в†’export function getClientIp(c: any): string | undefined {
 9в†’  return (
10в†’    (c.env as any)?.incoming?.socket?.remoteAddress ||
11в†’    c.req.header("x-forwarded-for")?.split(",")[0]?.trim() ||
12в†’    c.req.header("x-real-ip")
13в†’  );
14в†’}
