 1в†’// Deus Cloud Relay вЂ” Cloudflare Worker entry point.
 2в†’// Routes WebSocket upgrades to the RelayDO (one Durable Object per server).
 3в†’
 4в†’import { Hono } from "hono";
 5в†’import { cors } from "hono/cors";
 6в†’import { createMiddleware } from "hono/factory";
 7в†’import type { Bindings } from "./types";
 8в†’
 9в†’export { RelayDO } from "./relay-do";
10в†’
11в†’const app = new Hono<{ Bindings: Bindings }>();
12в†’
13в†’// CORS for web portal and local dev
14в†’app.use(
15в†’  "*",
16в†’  cors({
17в†’    origin: ["https://app.rundeus.com", "http://localhost:3000", "http://localhost:5173"],
18в†’    allowMethods: ["GET", "POST", "OPTIONS"],
19в†’    allowHeaders: ["Content-Type", "Authorization"],
20в†’  })
21в†’);
22в†’
23в†’// Middleware: validate serverId and attach DO stub to context
24в†’const withRelay = createMiddleware<{
25в†’  Bindings: Bindings;
26в†’  Variables: { stub: DurableObjectStub };
27в†’}>(async (c, next) => {
28в†’  const serverId = c.req.param("serverId");
29в†’  if (!serverId || !/^[a-z0-9]{4,8}$/i.test(serverId)) {
30в†’    return c.json({ error: "Invalid server ID" }, { status: 400 });
31в†’  }
32в†’  const id = c.env.RELAY.idFromName(serverId);
33в†’  c.set("stub", c.env.RELAY.get(id));
34в†’  await next();
35в†’});
36в†’
37в†’// Health check
38в†’app.get("/health", (c) =>
39в†’  c.json({
40в†’    status: "ok",
41в†’    timestamp: new Date().toISOString(),
42в†’    service: "deus-relay",
43в†’  })
44в†’);
45в†’
46в†’// Server tunnel вЂ” desktop server connects here to register with the relay
47в†’app.get("/api/servers/:serverId/tunnel", withRelay, async (c) => {
48в†’  const stub = c.get("stub");
49в†’  const tunnelUrl = new URL(c.req.url);
50в†’  tunnelUrl.pathname = "/tunnel";
51в†’  return stub.fetch(new Request(tunnelUrl, c.req.raw));
52в†’});
53в†’
54в†’// Client connect вЂ” remote web/mobile clients connect here
55в†’app.get("/api/servers/:serverId/connect", withRelay, async (c) => {
56в†’  const stub = c.get("stub");
57в†’  const connectUrl = new URL(c.req.url);
58в†’  connectUrl.pathname = "/connect";
59в†’  return stub.fetch(new Request(connectUrl, c.req.raw));
60в†’});
61в†’
62в†’// Pairing exchange вЂ” web portal exchanges a code for a device token
63в†’app.get("/api/servers/:serverId/pair", withRelay, async (c) => {
64в†’  const stub = c.get("stub");
65в†’  const pairUrl = new URL(c.req.url);
66в†’  pairUrl.pathname = "/pair";
67в†’  return stub.fetch(new Request(pairUrl, c.req.raw));
68в†’});
69в†’
70в†’// Server status вЂ” check if a server is online
71в†’app.get("/api/servers/:serverId/status", withRelay, async (c) => {
72в†’  const stub = c.get("stub");
73в†’  return stub.fetch(new Request(new URL("/status", c.req.url)));
74в†’});
75в†’
76в†’// Root
77в†’app.get("/", (c) =>
78в†’  c.json({
79в†’    name: "deus-relay",
80в†’    version: "0.1.0",
81в†’    docs: "https://app.rundeus.com",
82в†’  })
83в†’);
84в†’
85в†’export default app;
