  1в†’/**
  2в†’ * WebSocket Query Protocol Client
  3в†’ *
  4в†’ * Singleton client that connects to the backend's /ws endpoint and handles
  5в†’ * the q:* protocol for real-time data subscriptions, one-shot requests,
  6в†’ * mutations, and async commands.
  7в†’ *
  8в†’ * Protocol:
  9в†’ *   Client sends: q:subscribe, q:unsubscribe, q:request, q:mutate, q:command
 10в†’ *   Server sends: q:snapshot, q:delta, q:response, q:mutate_result, q:command_ack, q:error, q:event, ping
 11в†’ *   Client responds to ping with pong
 12в†’ *
 13в†’ * Relay mode (web-production):
 14в†’ *   Connects through cloud relay at wss://relay.rundeus.com/api/servers/{id}/connect
 15в†’ *   Sends { type: "authenticate", token } on open for device token auth.
 16в†’ *   Handles relay control frames: authenticated, auth_failed, server_reconnecting, server_connected.
 17в†’ *
 18в†’ * On reconnect, all active subscriptions are re-established automatically.
 19в†’ */
 20в†’
 21в†’import { match } from "ts-pattern";
 22в†’import { resolveBackendEndpoints, isRelayMode } from "@/shared/config/backend.config";
 23в†’import { getStoredToken, signOut } from "@/features/auth";
 24в†’import type { QueryResource, CommandName } from "@shared/types/query-protocol";
 25в†’
 26в†’// ---- Types ----
 27в†’
 28в†’type SnapshotCallback = (data: unknown) => void;
 29в†’type DeltaCallback = (upserted?: unknown[], removed?: string[], cursor?: number) => void;
 30в†’type EventCallback = (event: string, data: unknown) => void;
 31в†’
 32в†’interface PendingCommand {
 33в†’  resolve: (result: { accepted: boolean; commandId?: string; error?: string }) => void;
 34в†’  reject: (err: Error) => void;
 35в†’}
 36в†’
 37в†’interface PendingRequest {
 38в†’  resolve: (data: unknown) => void;
 39в†’  reject: (err: Error) => void;
 40в†’  timer: ReturnType<typeof setTimeout>;
 41в†’}
 42в†’
 43в†’interface PendingMutation {
 44в†’  resolve: (result: { success: boolean; data?: unknown; error?: string }) => void;
 45в†’  reject: (err: Error) => void;
 46в†’  timer: ReturnType<typeof setTimeout>;
 47в†’}
 48в†’
 49в†’interface Subscription {
 50в†’  id: string;
 51в†’  resource: QueryResource;
 52в†’  params?: Record<string, unknown>;
 53в†’  onSnapshot: SnapshotCallback;
 54в†’  onDelta?: DeltaCallback;
 55в†’}
 56в†’
 57в†’// ---- Reconnect Config ----
 58в†’
 59в†’const BACKOFF_BASE_MS = 500;
 60в†’const BACKOFF_MAX_MS = 8000;
 61в†’
 62в†’// ---- Singleton State ----
 63в†’
 64в†’let ws: WebSocket | null = null;
 65в†’let _connectionId: string | null = null;
 66в†’let connected = false;
 67в†’let connecting = false;
 68в†’let reconnectAttempt = 0;
 69в†’let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 70в†’let subCounter = 0;
 71в†’
 72в†’/** Active subscriptions keyed by client-assigned ID. */
 73в†’const subscriptions = new Map<string, Subscription>();
 74в†’
 75в†’/** Pending commands waiting for q:command_ack. */
 76в†’const pendingCommands = new Map<string, PendingCommand>();
 77в†’
 78в†’/** Pending one-shot q:request frames waiting for q:response. */
 79в†’const pendingRequests = new Map<string, PendingRequest>();
 80в†’
 81в†’/** Pending q:mutate frames waiting for q:mutate_result. */
 82в†’const pendingMutations = new Map<string, PendingMutation>();
 83в†’
 84в†’/** Listeners for q:event broadcasts. */
 85в†’const eventListeners = new Set<EventCallback>();
 86в†’
 87в†’/** Listeners notified when connection state changes (connected/disconnected). */
 88в†’const connectionChangeListeners = new Set<(connected: boolean) => void>();
 89в†’
 90в†’/** Counter for generating unique command frame IDs. */
 91в†’let commandCounter = 0;
 92в†’
 93в†’/** Counter for generating unique request/mutation frame IDs. */
 94в†’let requestCounter = 0;
 95в†’
 96в†’/** Resolvers waiting for the initial "connected" frame after open. */
 97в†’let connectResolve: (() => void) | null = null;
 98в†’let connectReject: ((err: Error) => void) | null = null;
 99в†’
100в†’// ---- Public API ----
101в†’
102в†’/** Generate a unique subscription ID. */
103в†’function nextSubId(): string {
104в†’  return `sub_${++subCounter}`;
105в†’}
106в†’
107в†’/**
108в†’ * Connect to the backend WebSocket. Resolves once authenticated.
109в†’ * No-op if already connected or connecting.
110в†’ *
111в†’ * In relay mode, pass the serverId so the WS URL can be resolved.
112в†’ */
113в†’export async function connect(serverId?: string): Promise<void> {
114в†’  // Detect stale socket: `connected` flag says yes but the actual WebSocket is dead.
115в†’  // This happens after Vite HMR reloads вЂ” module state is preserved but the socket
116в†’  // reference is stale (readyState !== OPEN). Force reconnect in this case.
117в†’  if (connected && (!ws || ws.readyState !== WebSocket.OPEN)) {
118в†’    connected = false;
119в†’    connecting = false;
120в†’    _connectionId = null;
121в†’    if (ws) {
122в†’      const staleWs = ws;
123в†’      ws = null;
124в†’      staleWs.onclose = null;
125в†’      try {
126в†’        staleWs.close();
127в†’      } catch {
128в†’        /* ignore */
129в†’      }
130в†’    }
131в†’    notifyConnectionChange(false);
132в†’  }
133в†’  if (connected) return;
134в†’  if (connecting) {
135в†’    // Wait for the in-flight connection attempt
136в†’    return new Promise<void>((resolve, reject) => {
137в†’      const prevResolve = connectResolve;
138в†’      const prevReject = connectReject;
139в†’      connectResolve = () => {
140в†’        prevResolve?.();
141в†’        resolve();
142в†’      };
143в†’      connectReject = (err) => {
144в†’        prevReject?.(err);
145в†’        reject(err);
146в†’      };
147в†’    });
148в†’  }
149в†’
150в†’  connecting = true;
151в†’
152в†’  return new Promise<void>((resolve, reject) => {
153в†’    connectResolve = resolve;
154в†’    connectReject = reject;
155в†’    openSocket(serverId).catch((err) => {
156в†’      connecting = false;
157в†’      connectReject?.(err);
158в†’      connectResolve = null;
159в†’      connectReject = null;
160в†’    });
161в†’  });
162в†’}
163в†’
164в†’/**
165в†’ * Subscribe to a query resource. Returns an unsubscribe function.
166в†’ *
167в†’ * On subscription, the server sends an initial q:snapshot. Subsequent
168в†’ * invalidations push q:snapshot (full replace) or q:delta (incremental).
169в†’ */
170в†’export function subscribe(
171в†’  resource: QueryResource,
172в†’  params: Record<string, unknown> | undefined,
173в†’  onSnapshot: SnapshotCallback,
174в†’  onDelta?: DeltaCallback
175в†’): () => void {
176в†’  const id = nextSubId();
177в†’  const sub: Subscription = { id, resource, params, onSnapshot, onDelta };
178в†’  subscriptions.set(id, sub);
179в†’
180в†’  // If connected, send subscribe frame immediately
181в†’  if (connected && ws) {
182в†’    sendFrame({
183в†’      type: "q:subscribe",
184в†’      id,
185в†’      resource,
186в†’      ...(params ? { params } : {}),
187в†’    });
188в†’  }
189в†’
190в†’  // Return unsubscribe function
191в†’  return () => {
192в†’    subscriptions.delete(id);
193в†’    if (connected && ws) {
194в†’      sendFrame({ type: "q:unsubscribe", id });
195в†’    }
196в†’  };
197в†’}
198в†’
199в†’/** Check if the client is currently connected. */
200в†’export function isConnected(): boolean {
201в†’  return connected;
202в†’}
203в†’
204в†’/**
205в†’ * Send an async command via the q:command frame.
206в†’ * Returns a promise that resolves when the server sends q:command_ack.
207в†’ * @param timeoutMs вЂ” override default 30s timeout (e.g. 300_000 for long-running commands like git:clone)
208в†’ */
209в†’export function sendCommand(
210в†’  command: CommandName,
211в†’  params: Record<string, unknown>,
212в†’  timeoutMs = 30_000
213в†’): Promise<{ accepted: boolean; commandId?: string; error?: string }> {
214в†’  const id = `cmd_${++commandCounter}`;
215в†’
216в†’  return new Promise((resolve, reject) => {
217в†’    pendingCommands.set(id, { resolve, reject });
218в†’
219в†’    const sent = sendFrame({
220в†’      type: "q:command",
221в†’      id,
222в†’      command,
223в†’      params,
224в†’    });
225в†’
226в†’    // Reject immediately if the frame couldn't be sent (WS disconnected)
227в†’    if (!sent) {
228в†’      pendingCommands.delete(id);
229в†’      reject(new Error("WebSocket not connected"));
230в†’      return;
231в†’    }
232в†’
233в†’    // Timeout to prevent leaked promises
234в†’    setTimeout(() => {
235в†’      if (pendingCommands.has(id)) {
236в†’        pendingCommands.delete(id);
237в†’        reject(new Error(`Command ${command} timed out`));
238в†’      }
239в†’    }, timeoutMs);
240в†’  });
241в†’}
242в†’
243в†’/**
244в†’ * Send a one-shot data request via the q:request frame.
245в†’ * Returns a promise that resolves with the response data when the
246в†’ * server sends q:response, or rejects on q:error or timeout.
247в†’ *
248в†’ * Works with both subscribable (QueryResource) and request-only
249в†’ * (RequestResource) resources.
250в†’ */
251в†’export function sendRequest<T = unknown>(
252в†’  resource: string,
253в†’  params?: Record<string, unknown>
254в†’): Promise<T> {
255в†’  const id = `req_${++requestCounter}`;
256в†’  const REQUEST_TIMEOUT_MS = 30_000;
257в†’
258в†’  return new Promise<T>((resolve, reject) => {
259в†’    const timer = setTimeout(() => {
260в†’      pendingRequests.delete(id);
261в†’      reject(new Error(`Request ${resource} timed out`));
262в†’    }, REQUEST_TIMEOUT_MS);
263в†’
264в†’    pendingRequests.set(id, {
265в†’      resolve: resolve as (data: unknown) => void,
266в†’      reject,
267в†’      timer,
268в†’    });
269в†’
270в†’    const sent = sendFrame({
271в†’      type: "q:request",
272в†’      id,
273в†’      resource,
274в†’      ...(params ? { params } : {}),
275в†’    });
276в†’
277в†’    if (!sent) {
278в†’      clearTimeout(timer);
279в†’      pendingRequests.delete(id);
280в†’      reject(new Error("WebSocket not connected"));
281в†’    }
282в†’  });
283в†’}
284в†’
285в†’/**
286в†’ * Send a mutation via the q:mutate frame.
287в†’ * Returns a promise that resolves with the mutation result when the
288в†’ * server sends q:mutate_result, or rejects on timeout.
289в†’ */
290в†’export function sendMutate<T = unknown>(
291в†’  action: string,
292в†’  params: Record<string, unknown>
293в†’): Promise<{ success: boolean; data?: T; error?: string }> {
294в†’  const id = `mut_${++requestCounter}`;
295в†’  const MUTATE_TIMEOUT_MS = 30_000;
296в†’
297в†’  return new Promise((resolve, reject) => {
298в†’    const timer = setTimeout(() => {
299в†’      pendingMutations.delete(id);
300в†’      reject(new Error(`Mutation ${action} timed out`));
301в†’    }, MUTATE_TIMEOUT_MS);
302в†’
303в†’    pendingMutations.set(id, {
304в†’      resolve: resolve as (result: { success: boolean; data?: unknown; error?: string }) => void,
305в†’      reject,
306в†’      timer,
307в†’    });
308в†’
309в†’    const sent = sendFrame({
310в†’      type: "q:mutate",
311в†’      id,
312в†’      action,
313в†’      params,
314в†’    });
315в†’
316в†’    if (!sent) {
317в†’      clearTimeout(timer);
318в†’      pendingMutations.delete(id);
319в†’      reject(new Error("WebSocket not connected"));
320в†’    }
321в†’  });
322в†’}
323в†’
324в†’/**
325в†’ * Register a callback for q:event broadcasts.
326в†’ * Returns an unregister function.
327в†’ */
328в†’export function onEvent(callback: EventCallback): () => void {
329в†’  eventListeners.add(callback);
330в†’  return () => {
331в†’    eventListeners.delete(callback);
332в†’  };
333в†’}
334в†’
335в†’/**
336в†’ * Send a tool response back to the backend (q:tool_response frame).
337в†’ * Used by frontend RPC handlers to respond to tool relay requests
338в†’ * received via q:event with event: "tool:request".
339в†’ */
340в†’export function sendToolResponse(requestId: string, result?: unknown, error?: string): boolean {
341в†’  const frame: Record<string, unknown> = {
342в†’    type: "q:tool_response",
343в†’    requestId,
344в†’  };
345в†’  if (error !== undefined) {
346в†’    frame.error = error;
347в†’  } else {
348в†’    frame.result = result;
349в†’  }
350в†’  return sendFrame(frame);
351в†’}
352в†’
353в†’/**
354в†’ * Force an immediate reconnection to the backend.
355в†’ * Used when the backend restarts on a new port вЂ” cancels any pending
356в†’ * backoff timer and closes the stale socket so reconnection picks up
357в†’ * the new port from getBackendPort().
358в†’ */
359в†’export function forceReconnect(): void {
360в†’  // Cancel any pending reconnect timer so we don't double-connect
361в†’  if (reconnectTimer) {
362в†’    clearTimeout(reconnectTimer);
363в†’    reconnectTimer = null;
364в†’  }
365в†’
366в†’  // Reset backoff counter so the immediate attempt uses minimal delay
367в†’  reconnectAttempt = 0;
368в†’
369в†’  // Close existing socket (if open) вЂ” onclose handler will NOT auto-schedule
370в†’  // because we immediately trigger our own reconnect below.
371в†’  if (ws) {
372в†’    // Prevent the onclose handler from scheduling its own reconnect
373в†’    const staleWs = ws;
374в†’    ws = null;
375в†’    connected = false;
376в†’    connecting = false;
377в†’    _connectionId = null;
378в†’    staleWs.onclose = null;
379в†’    staleWs.close();
380в†’
381в†’    notifyConnectionChange(false);
382в†’  }
383в†’
384в†’  // Immediately open a new socket (reads fresh port from getBackendPort())
385в†’  connecting = true;
386в†’  openSocket().catch(() => {
387в†’    connecting = false;
388в†’    // If this fails, fall back to normal backoff reconnect
389в†’    scheduleReconnect();
390в†’  });
391в†’}
392в†’
393в†’/**
394в†’ * Register a callback for connection state changes.
395в†’ * Fires with `true` when connected, `false` when disconnected.
396в†’ * Used by useQuerySubscription to re-evaluate subscriptions after reconnect.
397в†’ * Returns an unregister function.
398в†’ */
399в†’export function onConnectionChange(callback: (connected: boolean) => void): () => void {
400в†’  connectionChangeListeners.add(callback);
401в†’  return () => {
402в†’    connectionChangeListeners.delete(callback);
403в†’  };
404в†’}
405в†’
406в†’// ---- Internal ----
407в†’
408в†’async function openSocket(serverId?: string): Promise<void> {
409в†’  const endpoints = await resolveBackendEndpoints(serverId);
410в†’  const url = endpoints.wsUrl;
411в†’  const relay = isRelayMode();
412в†’
413в†’  ws = new WebSocket(url);
414в†’
415в†’  ws.onopen = () => {
416в†’    if (relay) {
417в†’      // Relay mode: send authenticate frame with device token
418в†’      const token = getStoredToken();
419в†’      if (token) {
420в†’        sendFrame({ type: "authenticate", token });
421в†’      } else {
422в†’        // No token available вЂ” close and surface auth failure
423в†’        console.error("[WS] Relay mode: no device token available for authentication");
424в†’        ws?.close(4001, "No device token");
425в†’      }
426в†’    }
427в†’    // Localhost/web-dev connections are auto-authenticated by the backend.
428в†’    // Wait for the "connected" frame in onmessage.
429в†’  };
430в†’
431в†’  ws.onmessage = (evt) => {
432в†’    let msg: Record<string, unknown>;
433в†’    try {
434в†’      msg = JSON.parse(evt.data as string);
435в†’    } catch {
436в†’      return;
437в†’    }
438в†’
439в†’    const type = typeof msg.type === "string" ? msg.type : "";
440в†’
441в†’    match(type)
442в†’      .with("connected", () => {
443в†’        // Localhost/web-dev: backend sends "connected" after auto-auth
444в†’        _connectionId = msg.connectionId as string;
445в†’        connected = true;
446в†’        connecting = false;
447в†’        reconnectAttempt = 0;
448в†’
449в†’        resubscribeAll();
450в†’        notifyConnectionChange(true);
451в†’
452в†’        connectResolve?.();
453в†’        connectResolve = null;
454в†’        connectReject = null;
455в†’      })
456в†’      .with("authenticated", () => {
457в†’        // Relay mode: relay confirms device token is valid
458в†’        connected = true;
459в†’        connecting = false;
460в†’        reconnectAttempt = 0;
461в†’
462в†’        resubscribeAll();
463в†’        notifyConnectionChange(true);
464в†’
465в†’        connectResolve?.();
466в†’        connectResolve = null;
467в†’        connectReject = null;
468в†’      })
469в†’      .with("auth_failed", () => {
470в†’        // Relay mode: device token rejected вЂ” sign out (clears storage + React state)
471в†’        console.error("[WS] Relay auth failed:", msg.message);
472в†’        signOut();
473в†’
474в†’        // Prevent the onclose handler from triggering a reconnect loop
475в†’        connected = false;
476в†’        subscriptions.clear();
477в†’        if (ws) {
478в†’          ws.onclose = null;
479в†’          ws.close(4001, "Auth failed");
480в†’          ws = null;
481в†’        }
482в†’
483в†’        connecting = false;
484в†’        connectReject?.(new Error(`Relay auth failed: ${msg.message}`));
485в†’        connectResolve = null;
486в†’        connectReject = null;
487в†’
488в†’        notifyConnectionChange(false);
489в†’      })
490в†’      .with("server_reconnecting", () => {
491в†’        // Relay mode: desktop server disconnected from relay, waiting for reconnect.
492в†’        // Mark as disconnected so isConnected() returns false вЂ” q:request/q:mutate
493в†’        // will reject immediately instead of sending frames that will time out.
494в†’        // Keep the WS open вЂ” relay will send "server_connected" when server returns.
495в†’        if (import.meta.env.DEV) {
496в†’          console.log("[WS] Server reconnecting (relay):", msg);
497в†’        }
498в†’        connected = false;
499в†’
500в†’        // Reject all pending one-shot requests and mutations
501в†’        for (const [_id, pending] of pendingRequests) {
502в†’          clearTimeout(pending.timer);
503в†’          pending.reject(new Error("Server disconnected вЂ” reconnecting"));
504в†’        }
505в†’        pendingRequests.clear();
506в†’
507в†’        for (const [_id, pending] of pendingMutations) {
508в†’          clearTimeout(pending.timer);
509в†’          pending.reject(new Error("Server disconnected вЂ” reconnecting"));
510в†’        }
511в†’        pendingMutations.clear();
512в†’
513в†’        notifyConnectionChange(false);
514в†’      })
515в†’      .with("server_connected", () => {
516в†’        // Relay mode: desktop server reconnected to relay.
517в†’        // Re-subscribe all active subscriptions.
518в†’        if (import.meta.env.DEV) {
519в†’          console.log("[WS] Server reconnected (relay)");
520в†’        }
521в†’        connected = true;
522в†’        resubscribeAll();
523в†’        notifyConnectionChange(true);
524в†’      })
525в†’      .with("ping", () => {
526в†’        sendFrame({ type: "pong" });
527в†’      })
528в†’      .with("q:snapshot", () => {
529в†’        const sub = subscriptions.get(msg.id as string);
530в†’        sub?.onSnapshot(msg.data);
531в†’      })
532в†’      .with("q:delta", () => {
533в†’        const sub = subscriptions.get(msg.id as string);
534в†’        sub?.onDelta?.(
535в†’          msg.upserted as unknown[] | undefined,
536в†’          msg.removed as string[] | undefined,
537в†’          msg.cursor as number | undefined
538в†’        );
539в†’      })
540в†’      .with("q:command_ack", () => {
541в†’        const pending = pendingCommands.get(msg.id as string);
542в†’        if (pending) {
543в†’          pendingCommands.delete(msg.id as string);
544в†’          pending.resolve({
545в†’            accepted: msg.accepted as boolean,
546в†’            commandId: msg.commandId as string | undefined,
547в†’            error: msg.error as string | undefined,
548в†’          });
549в†’        }
550в†’      })
551в†’      .with("q:event", () => {
552в†’        const event = msg.event as string;
553в†’        const data = msg.data;
554в†’        for (const cb of eventListeners) {
555в†’          try {
556в†’            cb(event, data);
557в†’          } catch (err) {
558в†’            console.error("[WS] Event listener error:", err);
559в†’          }
560в†’        }
561в†’      })
562в†’      .with("q:response", () => {
563в†’        // One-shot q:request response
564в†’        const id = msg.id as string;
565в†’        const pending = pendingRequests.get(id);
566в†’        if (pending) {
567в†’          clearTimeout(pending.timer);
568в†’          pendingRequests.delete(id);
569в†’          pending.resolve(msg.data);
570в†’        }
571в†’      })
572в†’      .with("q:mutate_result", () => {
573в†’        // Mutation result
574в†’        const id = msg.id as string;
575в†’        const pending = pendingMutations.get(id);
576в†’        if (pending) {
577в†’          clearTimeout(pending.timer);
578в†’          pendingMutations.delete(id);
579в†’          pending.resolve({
580в†’            success: msg.success as boolean,
581в†’            data: msg.data as unknown,
582в†’            error: msg.error as string | undefined,
583в†’          });
584в†’        }
585в†’      })
586в†’      .with("q:error", () => {
587в†’        const id = msg.id as string;
588в†’        const errorMsg = (msg.message as string) || "Query error";
589в†’
590в†’        // Check if this error is for a pending request
591в†’        const pendingReq = pendingRequests.get(id);
592в†’        if (pendingReq) {
593в†’          clearTimeout(pendingReq.timer);
594в†’          pendingRequests.delete(id);
595в†’          pendingReq.reject(new Error(errorMsg));
596в†’          return;
597в†’        }
598в†’
599в†’        // Check if this error is for a pending mutation
600в†’        const pendingMut = pendingMutations.get(id);
601в†’        if (pendingMut) {
602в†’          clearTimeout(pendingMut.timer);
603в†’          pendingMutations.delete(id);
604в†’          pendingMut.reject(new Error(errorMsg));
605в†’          return;
606в†’        }
607в†’
608в†’        // Subscription error (existing behavior)
609в†’        console.warn("[WS] Query error:", msg.message, "for sub:", id);
610в†’      })
611в†’      .otherwise(() => {
612в†’        // Ignore unknown frame types
613в†’      });
614в†’  };
615в†’
616в†’  ws.onerror = () => {
617в†’    // onerror fires before onclose вЂ” actual cleanup happens in onclose
618в†’  };
619в†’
620в†’  ws.onclose = () => {
621в†’    const wasConnected = connected;
622в†’    connected = false;
623в†’    _connectionId = null;
624в†’    ws = null;
625в†’
626в†’    // Reject all pending commands immediately вЂ” they can't succeed without a connection
627в†’    for (const [_id, pending] of pendingCommands) {
628в†’      pending.reject(new Error("WebSocket disconnected"));
629в†’    }
630в†’    pendingCommands.clear();
631в†’
632в†’    // Reject all pending one-shot requests
633в†’    for (const [_id, pending] of pendingRequests) {
634в†’      clearTimeout(pending.timer);
635в†’      pending.reject(new Error("WebSocket disconnected вЂ” request failed"));
636в†’    }
637в†’    pendingRequests.clear();
638в†’
639в†’    // Reject all pending mutations
640в†’    for (const [_id, pending] of pendingMutations) {
641в†’      clearTimeout(pending.timer);
642в†’      pending.reject(new Error("WebSocket disconnected вЂ” mutation failed"));
643в†’    }
644в†’    pendingMutations.clear();
645в†’
646в†’    if (connecting) {
647в†’      // Initial connection failed вЂ” reject the connect() promise
648в†’      connecting = false;
649в†’      connectReject?.(new Error("WebSocket connection failed"));
650в†’      connectResolve = null;
651в†’      connectReject = null;
652в†’    }
653в†’
654в†’    if (wasConnected) {
655в†’      notifyConnectionChange(false);
656в†’    }
657в†’
658в†’    // Only auto-reconnect if we had previously connected or have active subscriptions
659в†’    if (wasConnected || subscriptions.size > 0) {
660в†’      scheduleReconnect();
661в†’    }
662в†’  };
663в†’}
664в†’
665в†’/** Notify all connection change listeners. */
666в†’function notifyConnectionChange(state: boolean): void {
667в†’  for (const cb of connectionChangeListeners) {
668в†’    try {
669в†’      cb(state);
670в†’    } catch (err) {
671в†’      console.error("[WS] Connection change listener error:", err);
672в†’    }
673в†’  }
674в†’}
675в†’
676в†’function sendFrame(frame: Record<string, unknown>): boolean {
677в†’  if (ws && ws.readyState === WebSocket.OPEN) {
678в†’    try {
679в†’      ws.send(JSON.stringify(frame));
680в†’      return true;
681в†’    } catch {
682в†’      // Connection may have closed between readyState check and send
683в†’      console.warn(`[WS] Failed to send ${frame.type} frame: connection closed during send`);
684в†’      return false;
685в†’    }
686в†’  }
687в†’  console.warn(`[WS] Dropped ${frame.type} frame: WebSocket not connected`);
688в†’  return false;
689в†’}
690в†’
691в†’/** Re-subscribe all active subscriptions after reconnect. */
692в†’function resubscribeAll(): void {
693в†’  for (const sub of subscriptions.values()) {
694в†’    sendFrame({
695в†’      type: "q:subscribe",
696в†’      id: sub.id,
697в†’      resource: sub.resource,
698в†’      ...(sub.params ? { params: sub.params } : {}),
699в†’    });
700в†’  }
701в†’}
702в†’
703в†’/** Schedule a reconnection with exponential backoff. */
704в†’function scheduleReconnect(): void {
705в†’  if (reconnectTimer) return;
706в†’
707в†’  const delay = Math.min(BACKOFF_BASE_MS * Math.pow(2, reconnectAttempt), BACKOFF_MAX_MS);
708в†’  reconnectAttempt++;
709в†’
710в†’  if (import.meta.env.DEV) {
711в†’    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})`);
712в†’  }
713в†’
714в†’  reconnectTimer = setTimeout(() => {
715в†’    reconnectTimer = null;
716в†’    connecting = true;
717в†’
718в†’    // Set up resolve/reject so subscriptions get re-established
719в†’    connectResolve = null;
720в†’    connectReject = null;
721в†’
722в†’    openSocket().catch(() => {
723в†’      connecting = false;
724в†’      // onclose handler will schedule another reconnect
725в†’    });
726в†’  }, delay);
727в†’}
