 30в†’function timeAgo(dateStr: string): string {
 31в†’  const diff = Date.now() - new Date(dateStr).getTime();
 32в†’  const minutes = Math.floor(diff / 60_000);
 33в†’  if (minutes < 1) return "just now";
 34в†’  if (minutes < 60) return `${minutes}m ago`;
 35в†’  const hours = Math.floor(minutes / 60);
 36в†’  if (hours < 24) return `${hours}h ago`;
 37в†’  const days = Math.floor(hours / 24);
 38в†’  return `${days}d ago`;
 39в†’}
