 41в†’function getDeviceIcon(ua: string | null) {
 42в†’  if (!ua) return Monitor;
 43в†’  const lower = ua.toLowerCase();
 44в†’  if (lower.includes("mobile") || lower.includes("iphone") || lower.includes("android")) {
 45в†’    return Smartphone;
 46в†’  }
 47в†’  return Monitor;
 48в†’}
