 50в†’/** Build the full pairing URL for QR code. */
 51в†’function buildPairUrl(accessUrl: string, code: string): string {
 52в†’  // accessUrl is like https://app.rundeus.com/connect/{serverId}
 53в†’  // Append ?pair=SOFT+TIGER (URL-encode the space as +)
 54в†’  const encodedCode = code.replace(/ /g, "+");
 55в†’  return `${accessUrl}?pair=${encodedCode}`;
 56в†’}
