119в†’/**
120в†’ * Connect Device Dialog -- shows QR code + code + countdown.
121в†’ * Code state is owned by the parent so it survives close/reopen.
122в†’ */
123в†’function ConnectDeviceDialog({
124в†’  open,
125в†’  onOpenChange,
126в†’  accessUrl,
127в†’  pairCode,
128в†’  countdown,
129в†’  isGenerating,
130в†’  onGenerate,
131в†’  devices,
132в†’  isDevicesLoaded,
133в†’}: {
134в†’  open: boolean;
135в†’  onOpenChange: (open: boolean) => void;
136в†’  accessUrl: string | null;
137в†’  pairCode: string | null;
138в†’  countdown: number;
139в†’  isGenerating: boolean;
140в†’  onGenerate: () => void;
141в†’  devices: PairedDevice[];
142в†’  isDevicesLoaded: boolean;
143в†’}) {
144в†’  const [prevDeviceIds, setPrevDeviceIds] = useState<Set<string>>(
145в†’    () => new Set(devices.map((d) => d.id))
146в†’  );
147в†’  const [showSuccess, setShowSuccess] = useState(false);
148в†’
149в†’  // Keep a stable ref of onOpenChange to avoid stale closures in setTimeout
150в†’  const onOpenChangeRef = useRef(onOpenChange);
151в†’  useEffect(() => {
152в†’    onOpenChangeRef.current = onOpenChange;
153в†’  }, [onOpenChange]);
154в†’
155в†’  // Generate code on first open if none exists
156в†’  useEffect(() => {
157в†’    if (open && !pairCode && !isGenerating) {
158в†’      onGenerate();
159в†’    }
160в†’    if (!open) {
161в†’      setShowSuccess(false);
162в†’    }
163в†’    // eslint-disable-next-line react-hooks/exhaustive-deps
164в†’  }, [open]);
165в†’
166в†’  // Detect successful pairing by comparing device IDs.
167в†’  // Gate on isDevicesLoaded to prevent false positives when the query resolves
168в†’  // from [] to existing devices after the dialog opens.
169в†’  useEffect(() => {
170в†’    const currentIds = new Set(devices.map((d) => d.id));
171в†’
172в†’    if (!isDevicesLoaded) {
173в†’      // Query hasn't resolved yet вЂ” just update the baseline, don't detect
174в†’      setPrevDeviceIds(currentIds);
175в†’      return;
176в†’    }
177в†’
178в†’    const hasNewDevice = devices.some((d) => !prevDeviceIds.has(d.id));
179в†’
180в†’    if (open && hasNewDevice) {
181в†’      setShowSuccess(true);
182в†’      const timer = setTimeout(() => onOpenChangeRef.current(false), 2000);
183в†’      setPrevDeviceIds(currentIds);
184в†’      return () => clearTimeout(timer);
185в†’    }
186в†’    setPrevDeviceIds(currentIds);
187в†’    return undefined;
188в†’    // eslint-disable-next-line react-hooks/exhaustive-deps
189в†’  }, [devices, open, isDevicesLoaded]);
190в†’
191в†’  const pairUrl = accessUrl && pairCode ? buildPairUrl(accessUrl, pairCode) : null;
192в†’  const minutes = Math.floor(countdown / 60);
193в†’  const isExpiringSoon = countdown > 0 && countdown < 120;
