202в†’    }
203в†’  }
204в†’
205в†’  async function handleCopyLink() {
206в†’    if (!pairUrl) return;
207в†’    try {
208в†’      await navigator.clipboard.writeText(pairUrl);
209в†’      toast.success("Link copied");
210в†’    } catch {
211в†’      toast.error("Couldn't copy the link");
212в†’    }
213в†’  }
