215в†’  return (
216в†’    <Dialog open={open} onOpenChange={onOpenChange}>
217в†’      <DialogContent className="sm:max-w-md">
218в†’        {showSuccess ? (
219в†’          <div className="flex flex-col items-center gap-4 py-8">
220в†’            <div className="bg-success/10 flex size-16 items-center justify-center rounded-full">
221в†’              <Check className="text-success size-8" />
222в†’            </div>
223в†’            <div className="text-center">
224в†’              <DialogTitle className="text-lg font-semibold">Device Connected</DialogTitle>
225в†’              <DialogDescription className="text-muted-foreground mt-1 text-sm">
226в†’                You can now access your workspaces from this device.
227в†’              </DialogDescription>
228в†’            </div>
229в†’          </div>
230в†’        ) : (
231в†’          <>
232в†’            <DialogHeader className="text-center">
233в†’              <DialogTitle>Connect a Device</DialogTitle>
234в†’              <DialogDescription>
235в†’                Scan the QR code or enter the code on your other device.
236в†’              </DialogDescription>
237в†’            </DialogHeader>
238в†’
239в†’            <div className="flex flex-col items-center gap-5 pt-2">
240в†’              {/* QR Code -- hero element */}
241в†’              {pairUrl ? (
242в†’                <div className="rounded-xl bg-white p-3">
243в†’                  <QRCodeSVG value={pairUrl} size={180} level="M" />
244в†’                </div>
245в†’              ) : accessUrl ? (
246в†’                <div className="bg-muted/40 flex size-[204px] items-center justify-center rounded-xl">
247в†’                  <span className="text-muted-foreground text-sm">Generating...</span>
248в†’                </div>
249в†’              ) : (
250в†’                <div className="bg-muted/40 flex size-[204px] items-center justify-center rounded-xl">
251в†’                  <span className="text-muted-foreground px-4 text-center text-sm">
252в†’                    Waiting for connection...
253в†’                  </span>
254в†’                </div>
255в†’              )}
256в†’
257в†’              {/* Code display */}
258в†’              {pairCode ? (
259в†’                <p className="font-mono text-2xl font-bold tracking-wide">{pairCode}</p>
260в†’              ) : (
261в†’                <div className="bg-muted/40 h-8 w-40 animate-pulse rounded" />
262в†’              )}
263в†’
264в†’              {/* Action buttons вЂ” Copy Link is primary (higher conversion for web sharing) */}
265в†’              <div className="flex gap-2">
