350в†’// ---------------------------------------------------------------------------
351в†’// Main Section
352в†’// ---------------------------------------------------------------------------
353в†’
354в†’/**
355в†’ * Unified Access settings section.
356в†’ *
357в†’ * Hierarchy:
358в†’ *   1. Toggle + hero portal card (URL, status, copy)
359в†’ *   2. "+ Connect a Device" button that opens a dialog with QR + code
360в†’ *   3. Connected devices list
361в†’ */
362в†’export function AccessSection({ settings, saveSetting }: SettingsSectionProps) {
363в†’  const enabled = settings.remote_access_enabled === true;
364в†’
365в†’  // Remote access queries -- only active when enabled
366в†’  const devicesQuery = usePairedDevices(enabled);
367в†’  const relayQuery = useRelayStatus(enabled);
368в†’  const generateCodeMutation = useGeneratePairCode();
369в†’  const revokeDeviceMutation = useRevokeDevice();
370в†’
371в†’  // Dialog state
372в†’  const [dialogOpen, setDialogOpen] = useState(false);
373в†’
374в†’  // Code state -- lives here so it survives dialog close/reopen
375в†’  const [pairCode, setPairCode] = useState<string | null>(null);
376в†’  const [codeExpiresAt, setCodeExpiresAt] = useState(0);
377в†’  const [countdown, setCountdown] = useState(0);
378в†’
379в†’  // Countdown timer -- runs regardless of dialog open state
380в†’  useEffect(() => {
381в†’    if (!pairCode || codeExpiresAt <= 0) return;
382в†’    const tick = () => {
383в†’      const remaining = Math.max(0, Math.ceil((codeExpiresAt - Date.now()) / 1000));
384в†’      setCountdown(remaining);
385в†’      if (remaining <= 0) {
386в†’        setPairCode(null);
387в†’        setCodeExpiresAt(0);
388в†’      }
389в†’    };
390в†’    tick();
391в†’    const interval = setInterval(tick, 1000);
392в†’    return () => clearInterval(interval);
393в†’  }, [pairCode, codeExpiresAt]);
394в†’
395в†’  async function handleGenerateCode() {
396в†’    try {
397в†’      const result = await generateCodeMutation.mutateAsync();
398в†’      setPairCode(result.code);
399в†’      setCodeExpiresAt(Date.now() + result.expires_in_seconds * 1000);
400в†’    } catch {
401в†’      toast.error("Couldn't generate a code. Try again.");
402в†’    }
403в†’  }
404в†’
405в†’  // -- Handlers --
406в†’
407в†’  const handleToggle = useCallback(
408в†’    async (on: boolean) => {
409в†’      const ok = await saveSetting("remote_access_enabled", on);
410в†’      if (ok) {
411в†’        toast.success(on ? "Device connections enabled" : "Device connections disabled");
412в†’      }
413в†’    },
414в†’    [saveSetting]
415в†’  );
416в†’
417в†’  async function handleRemoveDevice(device: PairedDevice) {
418в†’    try {
419в†’      await revokeDeviceMutation.mutateAsync(device.id);
420в†’      toast.success(`Removed "${device.name}"`);
421в†’    } catch {
422в†’      toast.error("Couldn't remove device. Try again.");
423в†’    }
424в†’  }
425в†’
426в†’  // -- Derived values --
427в†’
428в†’  const relayStatus = relayQuery.data;
429в†’  const devices = devicesQuery.data ?? [];
430в†’
431в†’  // Derive web app URL from relay WebSocket URL
432в†’  // wss://relay.rundeus.com -> https://app.rundeus.com/connect/{serverId}
433в†’  const accessUrl = (() => {
434в†’    if (!relayStatus?.relayUrl || !relayStatus.serverId) return null;
435в†’    try {
436в†’      const url = new URL(relayStatus.relayUrl);
437в†’      const host = url.hostname;
438в†’      const domain = host.replace(/^relay\./, "app.");
439в†’      return `https://${domain}/connect/${relayStatus.serverId}`;
440в†’    } catch {
441в†’      return null;
442в†’    }
443в†’  })();
444в†’
445в†’  // -- Render --
446в†’
447в†’  return (
448в†’    <div className="space-y-6">
449в†’      {/* Header */}
450в†’      <div>
451в†’        <h3 className="text-base font-semibold">Remote Access</h3>
452в†’        <p className="text-muted-foreground mt-1 text-sm">
453в†’          Access your workspaces from your phone or another computer.
454в†’        </p>
455в†’      </div>
456в†’
457в†’      {/* Master toggle */}
458в†’      <div className="flex items-center justify-between">
459в†’        <div>
460в†’          <Label htmlFor="remote-access-toggle" className="text-sm">
461в†’            Enable remote access
462в†’          </Label>
463в†’          <p className="text-muted-foreground text-xs">
464в†’            Allow other devices to connect to this machine.
465в†’          </p>
466в†’        </div>
467в†’        <Switch id="remote-access-toggle" checked={enabled} onCheckedChange={handleToggle} />
468в†’      </div>
469в†’
470в†’      {/* ----- Everything below is gated on the toggle ----- */}
471в†’
472в†’      {enabled && (
473в†’        <>
474в†’          {/* Portal card -- hero element: URL + status */}
475в†’          {accessUrl && relayStatus && (
476в†’            <PortalCard
477в†’              url={accessUrl}
478в†’              connected={relayStatus.connected}
479в†’              clients={relayStatus.clients}
480в†’            />
481в†’          )}
482в†’
483в†’          {/* Disconnected state without URL */}
484в†’          {relayStatus && !accessUrl && (
485в†’            <div className="bg-muted/30 flex items-center gap-2.5 rounded-lg px-4 py-3">
486в†’              <span className="bg-warning size-[7px] shrink-0 rounded-full" />
487в†’              <span className="text-muted-foreground text-sm">
488в†’                {relayStatus.connected ? "Setting up..." : "Connecting..."}
489в†’              </span>
490в†’            </div>
491в†’          )}
492в†’
493в†’          <Separator />
494в†’
495в†’          {/* Connect a Device button */}
496в†’          <div className="space-y-3">
497в†’            <Button variant="outline" size="sm" onClick={() => setDialogOpen(true)}>
498в†’              <Plus className="mr-1.5 size-3.5" />
499в†’              Connect a Device
500в†’            </Button>
501в†’          </div>
502в†’
503в†’          {/* Connect Device Dialog */}
504в†’          <ConnectDeviceDialog
505в†’            open={dialogOpen}
506в†’            onOpenChange={setDialogOpen}
507в†’            accessUrl={accessUrl}
508в†’            pairCode={pairCode}
509в†’            countdown={countdown}
510в†’            isGenerating={generateCodeMutation.isPending}
511в†’            onGenerate={handleGenerateCode}
512в†’            devices={devices}
513в†’            isDevicesLoaded={devicesQuery.isFetched}
514в†’          />
515в†’
516в†’          <Separator />
517в†’
518в†’          {/* Connected devices */}
519в†’          <div className="space-y-3">
520в†’            <div className="flex items-center gap-2">
521в†’              <h4 className="text-sm font-medium">Connected Devices</h4>
522в†’              {devices.length > 0 && (
523в†’                <Badge variant="secondary" className="text-[11px]">
524в†’                  {devices.length}
525в†’                </Badge>
526в†’              )}
527в†’            </div>
528в†’            <DevicesList
529в†’              devices={devices}
530в†’              onRemove={handleRemoveDevice}
531в†’              isRemoving={revokeDeviceMutation.isPending}
532в†’            />
533в†’          </div>
534в†’        </>
535в†’      )}
536в†’    </div>
537в†’  );
538в†’}
